inline.tests:
assert word_freq('') == {}
assert word_freq('hello') == {'hello': 1}
assert word_freq('Hello hello HELLO') == {'hello': 3}
assert word_freq('hello, world!') == {'hello': 1, 'world': 1}
assert word_freq('python3 is fun, python3 is cool.') == {'python3': 2, 'is': 2, 'fun': 1, 'cool': 1}
assert word_freq('a.b.c a') == {'a': 2, 'b': 1, 'c': 1}
assert word_freq('... !!! ???') == {}
assert word_freq('one\ntwo\tthree  four') == {'one': 1, 'two': 1, 'three': 1, 'four': 1}
assert word_freq('\u00e9clat') == {'clat': 1}
assert word_freq('cafe\u0301') == {'cafe': 1}
